#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
    int solve(std::vector<int>& boxes) {
        int crates = 1;
        int current_box = 0;
        for (int box : boxes) {
            if (box + current_box > 3) {
                crates++;
                current_box = 0;
            }
            current_box += box;
        }
        return crates;
    }
};

